internal static class LossPalette
{
    // (DotKey, TextKey, BgKey, 한국어 라벨, 툴팁)
    public static (string Dot, string Text, string Bg, string Label, string Tip) For(LossClass loss) => loss switch
    {
        LossClass.Lossless  => ("FsLossLosslessDot",  "FsLossLosslessText",  "FsLossLosslessBg",
                                "무손실",     "픽셀·내용을 완전 보존합니다"),
        LossClass.Container => ("FsLossContainerDot", "FsLossContainerText", "FsLossContainerBg",
                                "재포장",     "컨테이너·구조만 변경, 내용은 보존됩니다"),
        LossClass.Recode    => ("FsLossRecodeDot",    "FsLossRecodeText",    "FsLossRecodeBg",
                                "재인코딩",   "재인코딩으로 화질이 일부 손실됩니다"),
        LossClass.Rasterize => ("FsLossRasterizeDot", "FsLossRasterizeText", "FsLossRasterizeBg",
                                "래스터화",   "벡터·텍스트 편집성이 사라집니다 (단방향)"),
        _ => ("FsLossRecodeDot", "FsLossRecodeText", "FsLossRecodeBg", "재인코딩", ""),
    };

    // 배지/pill을 Recode·Rasterize일 때만 노출하는 절제 규칙
    public static Visibility PillVisibility(LossClass loss) =>
        loss is LossClass.Recode or LossClass.Rasterize
            ? Visibility.Visible : Visibility.Collapsed;
}

// 큐 전체에서 이 출력으로 갈 때의 '최악 손실 등급'을 산출 (Max severity)
private LossClass WorstLossFor(string outputExt)
{
    var graph = ((App)Application.Current).Engine.Providers.Graph;
    var worst = LossClass.Lossless;
    var inputs = _activeQueue.Count == 0
        ? Array.Empty<string>()
        : _activeQueue.Select(q => Path.GetExtension(q.SourcePath)).Distinct().ToArray();

    foreach (var input in inputs)
    {
        var path = graph.FindBestPath(input, outputExt, maxHops: 3, allowLossy: true);
        if (path is null) continue;
        foreach (var edge in path)            // 경로의 worst edge가 그 변환의 등급
            if ((int)edge.Loss > (int)worst) worst = edge.Loss;
    }
    return worst;   // enum 순서가 곧 심각도: Lossless<Container<Recode<Rasterize
}

private void UpdateLossGradeBadge(string? outputExt)
{
    if (LossGradeBadge is null || outputExt is null) return;
    var grade = WorstLossFor(outputExt);
    var (dot, text, bg, label, tip) = LossPalette.For(grade);
    LossGradeDot.Fill = (Brush)FindResource(dot);
    LossGradeLabel.Foreground = (Brush)FindResource(text);
    LossGradeBadge.Background = (Brush)FindResource(bg);
    LossGradeLabel.Text = grade == LossClass.Recode ? "재인코딩 (화질 손실)"
                        : grade == LossClass.Rasterize ? "래스터화 (편집성 상실)" : label;
    LossGradeBadge.ToolTip = tip;
    // 절제: 무손실/재포장은 배지를 조용히 숨김
    LossGradeBadge.Visibility = LossPalette.PillVisibility(grade);
}

